@Controller()
export class DisconnectedClientController {
  @Post()
  call(@Body() options): Observable<number> {
    const client = ClientProxyFactory.create(options);
    return client.send<number, number[]>({ cmd: 'none' }, [1, 2, 3]).pipe(
      // tap(
      //   console.log.bind(console, 'data'),
      //   console.error.bind(console, 'error'),
      // ),
      catchError(error => {
        const { code } = error?.err ?? error ?? { code: 'CONN_ERR' };
        return throwError(() =>
          code === 'ECONNREFUSED' ||
          code === 'CONN_ERR' ||
          code === 'ENOTFOUND' ||
          code === 'CONNECTION_REFUSED' ||
          error.message.includes('Connection is closed.')
            ? new RequestTimeoutException('ECONNREFUSED')
            : new InternalServerErrorException(),
        );
      }),
      tap({
        error: () => client.close(),
      }),
    );
  }
}

return (target: object, key: string | symbol | undefined, index?: number) => {
  let type = token || Reflect.getMetadata('design:type', target, key!);
  // Try to infer the token in a constructor-based injection
  if (!type && !injectCallHasArguments) {
    type = Reflect.getMetadata(PARAMTYPES_METADATA, target, key!)?.[index!];
  }

  if (!isUndefined(index)) {
    let dependencies =
      Reflect.getMetadata(SELF_DECLARED_DEPS_METADATA, target) || [];

    dependencies = [...dependencies, { index, param: type }];
    Reflect.defineMetadata(SELF_DECLARED_DEPS_METADATA, dependencies, target);
    return;
  }
  let properties =
    Reflect.getMetadata(PROPERTY_DEPS_METADATA, target.constructor) || [];

  properties = [...properties, { key, type }];
  Reflect.defineMetadata(
    PROPERTY_DEPS_METADATA,
    properties,
    target.constructor,
  );
};

getOrThrow<T = any>(propertyPath: KeyOf<K>): Exclude<T, undefined>;
  getOrThrow<
    T = K,
    P extends Path<T> = any,
    R extends PathValue<T, P> = PathValue<T, P>,
  >(propertyPath: P, options: ConfigGetOptions): Exclude<R, undefined>;
  getOrThrow<T = any>(
    propertyPath: KeyOf<K>,
    defaultValueOrOptions?: T | ConfigGetOptions,
    options?: ConfigGetOptions,
  ): Exclude<T, undefined> {
    // @ts-expect-error Bypass method overloads
    const value = this.get(propertyPath, defaultValueOrOptions, options) as
      | T
      | undefined;

    if (isUndefined(value)) {
      throw new TypeError(
        `Configuration key "${propertyPath.toString()}" does not exist`,
      );
    }

    return value as Exclude<T, undefined>;
  }

import { GraphQLScalarType, Kind, ValueNode } from 'graphql';

export const GraphQLTimestamp = new GraphQLScalarType({
  name: 'Timestamp',
  description:
    '`Date` type as integer. Type represents date and time as number of milliseconds from start of UNIX epoch.',
  serialize(value: Date) {
    return value instanceof Date ? value.getTime() : null;
  },
  parseValue(value: string | null) {
    try {
      return value !== null ? new Date(value) : null;
    } catch {
      return null;
    }
  },
  parseLiteral(ast: ValueNode) {
    if (ast.kind === Kind.INT) {
      const num = parseInt(ast.value, 10);
      return new Date(num);
    } else if (ast.kind === Kind.STRING) {
      return this.parseValue(ast.value);
    }
    return null;
  },
});

export function isInRootDirectory(
  host: Tree,
  extraFiles: string[] = [],
): boolean {
  const files = ['nest-cli.json', 'nest.json'].concat(extraFiles || []);
  return files.map((file) => host.exists(file)).some((isPresent) => isPresent);
}

export function mergeSourceRoot<
  T extends { sourceRoot?: string; path?: string } = any,
>(options: T): Rule {
  return (host: Tree) => {
    const isInRoot = isInRootDirectory(host, ['tsconfig.json', 'package.json']);
    if (!isInRoot) {
      return host;
    }
    const defaultSourceRoot =
      options.sourceRoot !== undefined ? options.sourceRoot : DEFAULT_PATH_NAME;

    options.path =
      options.path !== undefined
        ? join(normalize(defaultSourceRoot), options.path)
        : normalize(defaultSourceRoot);
    return host;
  };
}

if (authType === WebhookAuthEnum.TOKEN) {
  requestConfig.headers = {
    Authorization: cmd.auth?.token,
  };
} else if (authType === WebhookAuthEnum.API_KEY) {
  const addTo = cmd.auth?.addTo as WebhookApiKeyFieldEnum;

  if (addTo === WebhookApiKeyFieldEnum.HEADER) {
    requestConfig.headers = {
      [cmd.auth?.key]: cmd.auth?.value,
    };
  } else if (addTo === WebhookApiKeyFieldEnum.PARAMS) {
    requestConfig.url = `?${cmd.auth?.key}=${cmd.auth?.value}`;
  }
} else if (authType === WebhookAuthEnum.OAUTH_2) {
  const addTo = cmd.auth?.addTo as WebhookApiKeyFieldEnum;
  if (addTo === WebhookApiKeyFieldEnum.HEADER) {
    requestConfig.headers = {
      Authorization: cmd.auth?.token,
    };
  } else if (addTo === WebhookApiKeyFieldEnum.PARAMS) {
    requestConfig.url = `?Authorization=${cmd.auth?.token}`;
  }
}

if (
  versionOrVersions &&
  metadata.versioningOptions?.type === VersioningType.URI
) {
  const versionPrefix = this.getVersionPrefix(metadata.versioningOptions);

  if (Array.isArray(versionOrVersions)) {
    paths = flatten(
      paths.map(path =>
        versionOrVersions.map(version =>
          // Version Neutral - Do not include version in URL
          version === VERSION_NEUTRAL
            ? path
            : `${path}/${versionPrefix}${version}`,
        ),
      ),
    );
  } else {
    // Version Neutral - Do not include version in URL
    if (versionOrVersions !== VERSION_NEUTRAL) {
      paths = paths.map(
        path => `${path}/${versionPrefix}${versionOrVersions}`,
      );
    }
  }
}

return <TRequest extends Record<string, any> = any, TResponse = any>(
  req: TRequest,
  res: TResponse,
  next: () => void,
) => {
  (req as Record<string, any>).hosts = {};
  const hostname = httpAdapterRef.getRequestHostname(req) || '';

  for (const exp of hostRegExps) {
    const match = hostname.match(exp.regexp);
    if (match) {
      if (exp.keys.length > 0) {
        exp.keys.forEach((key, i) => (req.hosts[key.name] = match[i + 1]));
      } else if (exp.regexp && match.groups) {
        for (const groupName in match.groups) {
          req.hosts[groupName] = match.groups[groupName];
        }
      }
      return handler(req, res, next);
    }
  }
  if (!next) {
    throw new InternalServerErrorException(
      unsupportedFilteringErrorMessage,
    );
  }
  return next();
};

