export const getFilterOmitting = <DTO>(filter: Filter<DTO>, key: keyof DTO): Filter<DTO> =>
  Object.keys(filter).reduce<Filter<DTO>>((f, next) => {
    const omitted = { ...f };
    const k = next as keyof Filter<DTO>;
    if (k === 'and' && filter.and) {
      omitted.and = filter.and.map((part) => getFilterOmitting(part, key));
      if (omitted.and.every((part) => Object.keys(part).length === 0)) {
        delete omitted.and;
      }
    } else if (k === 'or' && filter.or) {
      omitted.or = filter.or.map((part) => getFilterOmitting(part, key));
      if (omitted.or.every((part) => Object.keys(part).length === 0)) {
        delete omitted.or;
      }
    } else if (k !== key) {
      omitted[k] = filter[k];
    }
    return omitted;
  }, {} as Filter<DTO>);

const _list = [SourceArticle, SourceMessage].map(item => {
  const schema = this.getCommentSchema(item);

  const date = moment();
  const list = [];
  for (let i = 0; i < size; i++) {

    const startDate = date.format(type === DateType.day ? 'YYYY-MM-DD' : 'YYYY-MM');
    const endDate = moment(startDate).add(1, type).format('YYYY-MM-DD');

    const findPromise = schema.countBy({
      createAt: Between(new Date(startDate + (type === DateType.day ? '' : '-01') + ' 00:00:00'), new Date(endDate + ' 23:59:59'))
    });

    list.push(findPromise.then(data => {
      return {
        date: startDate,
        count: data,
      }
    }));
    date.subtract(1, type);
  }
  return Promise.all(list);
});

if (this.isAWildcard(path)) {
  const entries =
    versionPaths.length > 0
      ? versionPaths
          .map(versionPath => [
            this.prefixPath + versionPath + '$',
            this.prefixPath + versionPath + addLeadingSlash(path),
          ])
          .flat()
      : this.prefixPath
        ? [this.prefixPath + '$', this.prefixPath + addLeadingSlash(path)]
        : [addLeadingSlash(path)];

  return Array.isArray(this.excludedGlobalPrefixRoutes)
    ? [
        ...entries,
        ...this.excludedGlobalPrefixRoutes
          .map(route =>
            Array.isArray(versionPaths) && versionPaths.length > 0
              ? versionPaths.map(v => v + addLeadingSlash(route.path))
              : addLeadingSlash(route.path),
          )
          .flat(),
      ]
    : entries;
}

